 reward tokens"},"initialize(address[],uint256)":{"notice":"Initializer for setting up strategy internal state. This overrides the InitializableAbstractStrategy initializer as Algebra strategies don't fit well within that abstraction."},"isGovernor()":{"notice":"Returns true if the caller is the current Governor."},"maxDepeg()":{"notice":"The max amount the OToken/asset price can deviate from peg (1e18) before deposits are reverted scaled to 18 decimals. eg 0.01e18 or 1e16 is 1% which is 100 basis points. This is the amount below and above peg so a 50 basis point deviation (0.005e18) allows a price range from 0.995 to 1.005."},"oToken()":{"notice":"Address of the OToken token contract."},"oTokenPoolIndex()":{"notice":"Index of the OToken in the Algebra pool."},"platformAddress()":{"notice":"Address of the underlying platform"},"pool()":{"notice":"Address of the Algebra Stable pool contract."},"removePToken(uint256)":{"notice":"Remove a supported asset by passing its index.      This method can only be called by the system Governor"},"rewardTokenAddresses(uint256)":{"notice":"Address of the reward tokens. eg CRV, BAL, CVX, AURA"},"safeApproveAllTokens()":{"notice":"Approve the spending of all assets by their corresponding pool tokens,      if for some reason is it necessary."},"setHarvesterAddress(address)":{"notice":"Set the Harvester contract that can collect rewards."},"setMaxDepeg(uint256)":{"notice":"Set the maximum deviation from the OToken/asset peg (1e18) before deposits are reverted."},"setPTokenAddress(address,address)":{"notice":"Provide support for asset by passing its pToken address.      This method can only be called by the system Governor"},"setRewardTokenAddresses(address[])":{"notice":"Set the reward token addresses. Any old addresses will be overwritten."},"supportsAsset(address)":{"notice":"Returns bool indicating whether asset is supported by strategy"},"swapAssetsToPool(uint256)":{"notice":"Used when there is more OToken than asset in the pool. 